  if(rst == 1) begin 
  snd <= 0; 
  counter <= 0; 
  end 
  if(counter == 0) begin 
  counter <= {divider,5'b0}; 
  if(divider != 0) 
  snd <= ~snd; 
  end 
  else 
  counter <= counter - 1; 
  end 
 endmodule

