module rtlpp_11457 (
    address,
    chipselect,
    clk,
    reset_n,
    write_n,
    writedata,
    out_port,
    readdata
);

  output           out_port;
  output  [31: 0]  readdata;
  input   [1: 0]   address;
  input            chipselect;
  input            clk;
  input            reset_n;
  input            write_n;
  input   [31: 0]  writedata;

  reg              data_out;
  wire             clk_en;
  wire             read_mux_out;
  wire    [31: 0]  readdata;
  wire             out_port;

  assign clk_en = 1;

  assign read_mux_out = (address == 0) ? data_out : 1'b0;

  always @(posedge clk or negedge reset_n)
  begin
    if (~reset_n)
      data_out <= 0;
    else if (chipselect && ~write_n && (address == 0))
      data_out <= writedata[0];  // Extract only the least significant bit of writedata as data_out is 1-bit
  end

  assign readdata = {31'b0, read_mux_out};
  assign out_port = data_out;

endmodule

