module autovcoder_103018 (
    input clk190hz,
    input [15:0] dataBus,
    output reg [3:0] pos,
    output reg [7:0] seg
);
  reg [1:0] posC;
  reg [3:0] dataP;
  always @(posedge clk190hz) begin
    case (posC)
      0: begin
        pos   <= 4'b0001;
        dataP <= dataBus[3:0];
      end

      1: begin
        pos   <= 4'b0010;
        dataP <= dataBus[7:4];
      end

      2: begin
        pos   <= 4'b0100;
        dataP <= dataBus[11:8];
      end

      3: begin
        pos   <= 4'b1000;
        dataP <= dataBus[15:12];
      end

    endcase
    if (posC == 4) posC = 0;
    else posC = posC + 1;
  end

  always @(dataP)
    case (dataP)
      0: seg = 8'b0111_0001;  // F
      1: seg = 8'b0000_0110;
      2: seg = 8'b0101_1011;
      3: seg = 8'b0100_1111;
      4: seg = 8'b0110_0110;
      5: seg = 8'b0011_1111;  // O
      6: seg = 8'b0011_1001;  // C
      7: seg = 8'b0011_1110;  // U
      8: seg = 8'b0101_1110;  // d
      9: seg = 8'b0110_1101;  // S
      default: seg = 8'b0000_1000;  // _
    endcase
endmodule

