        sum   = 1'b1;
        carry = 1'b0;
      end
      3'd5: begin
        sum   = 1'b0;
        carry = 1'b1;
      end
      3'd6: begin
        sum   = 1'b0;
        carry = 1'b1;
      end
      3'd7: begin
        sum   = 1'b1;
        carry = 1'b1;
      end
      default: begin
      end
    endcase
  end
endmodule

