module autovcoder_090681 (
    a,
    b,
    cin,
    sum,
    cout
);
  //input declaration
  input [23:0] a, b;
  input cin;
  //output declaration
  output [23:0] sum;
  output cout;
  //internal wires
  wire [1:0] C;
  wire [2:0] P, G;
  //code starts here
  //Carry Look-Ahead
  assign C[0] = G[0] | (P[0] & cin);
  assign C[1] = G[1] | (P[1] & G[0]) | (P[1] & P[0] & C[0]);

  // create 3 8-bit adders
  adder8 add0 (
      .a(a[7:0]),
      .b(b[7:0]),
      .cin(cin),
      .sum(sum[7:0]),
      .cout(),
      .PG(P[0]),
      .GG(G[0])
  );
  adder8 add1 (
      .a(a[15:8]),
      .b(b[15:8]),
      .cin(C[0]),
      .sum(sum[15:8]),
      .cout(),
      .PG(P[1]),
      .GG(G[1])
  );
  adder8 add2 (
      .a(a[23:16]),
      .b(b[23:16]),
      .cin(C[1]),
      .sum(sum[23:16]),
      .cout(cout),
      .PG(P[2]),
      .GG(G[2])
  );

endmodule

