  assign cmd_out[2] = (count >= 4 && cmd[0] && ~cmd[1] && ~cmd[2] && ~cmd[3]); 
  assign cmd_out[3] = (count >= 4 && cmd[0] && ~cmd[1] && ~cmd[2] && cmd[3]); 
  assign cmd_out[4] = (count >= 4 && cmd[0] && ~cmd[1] && cmd[2] && ~cmd[3]); 
