  assign cmd_out[5] = (count >= 8 && cmd[0] && cmd[1] && ~cmd[6] && ~cmd[7]); 
  assign cmd_out[6] = (count >= 8 && cmd[0] && cmd[1] && ~cmd[6] && cmd[7]); 
  assign cmd_out[7] = (count >= 8 && cmd[0] && cmd[1] && cmd[6] && ~cmd[7]); 
  assign cmd_out[8] = (count >= 8 && cmd[0] && cmd[1] && cmd[6] && cmd[7]); 
