reg [3:0] cnt; 
  reg [259:0] s; 
  reg [32:0] s1; 
  reg [64:0] k; 
  wire [34:0] k11 = {s1, 2'd0} + {s1, 1'd0} + s1; 
  wire [255:0] c1 = rx_a[511:256]; 
  reg [255:0] other; 
  wire [260:0] s_minus_p = s - 256'hFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFFEFFFFFC2F; 
  always @ (*) 
  begin 
  if (cnt == 0) 
  other <= {c1[223:0], 32'd0}; 
  else if (cnt == 1) 
  other <= {c1[246:0], 9'd0}; 
  else if (cnt == 2) 
  other <= {c1[247:0], 8'd0}; 
