  other <= {c1[251:0], 4'd0}; 
  else if (cnt == 6) 
  other <= c1; 
  else if (cnt == 7) 
  other <= k; 
  else 
  other <= k; 
  end 
  always @ (posedge clk) 
  begin 
  cnt <= cnt + 1; 
  s <= s + other; 
  if (cnt == 8) 
  begin 
  cnt <= cnt; 
  s <= s_minus_p; 
  if (s_minus_p[260] && !tx_done) 
