  initial o_wb_stb = 1'b0; 
  initial o_wb_addr= 0; 
  always @(posedge i_clk) 
  if ((i_rst)||(i_wb_ack)||(i_wb_err)) 
  begin 
  o_wb_cyc <= 1'b0; 
  o_wb_stb <= 1'b0; 
  end else if ((!o_wb_cyc)&&((i_stalled_n)||(!o_valid)||(i_new_pc))) 
  begin 
  o_wb_cyc <= 1'b1; 
  o_wb_stb <= 1'b1; 
  end else if (o_wb_cyc) 
  begin 
  if (!i_wb_stall) 
  o_wb_stb <= 1'b0; 
