        rotation_direction[7] = (rotation_angle[7] <= target_angle_clk) ? 1 : 0;
        x[8] = (rotation_direction[7] == 1) ? (x[7] - (y[7] >>> 7)) : (x[7] + (y[7] >>> 7));
