                pc_next = pc_inc;
          end
       endcase

       if (pause_in == 1'b1)
          pc_next = pc_reg;

       if(reset) begin
          pc_next0 = 30'b0;
          pc_next1 = 30'b0;
          pc_next2 = 30'b0;
          pc_next3 = 30'b0;
       end else begin
          case(thread_id)
