             2'b10: begin
                if(context_save == 1'b1)
                    pc_next2 = pc_next;
                if(context_restore == 1'b1)
                    pc_next = pc_next2;
             end
             2'b11: begin
                if(context_save == 1'b1)
                    pc_next3 = pc_next;
                if(context_restore == 1'b1)
                    pc_next = pc_next3;
             end
          endcase
       end
    end

endmodule

