module autovcoder_094900 (
    start,
    rst,
    r_in,
    a_out,
    a_in,
    r_out,
    f
);
  input start, rst, r_in, a_out;

  output a_in, r_out, f;

  wire clk, ack;
  wire a_and_r;
  wire r_in_net, a_out_net, a_and_r_net, f_net;
  wire ack_r_in, ack_a_out, ack_a_and_r, ack_f;
  wire a_and_r_net1, a_and_r_net2, a_and_r_net3;
  wire f_net1, f_net2, f_net3, f_net4;
  wire r_in_in, a_out_in, a_and_r_in, f_in;

  // Inputs
  q_flop qf_r_in (
      .rst (start),
      .clk (clk),
      .data(r_in_in),
      .ack (ack_r_in),
      .out (r_in_net)
  );
  q_flop qf_a_out (
      .rst (start),
      .clk (clk),
      .data(a_out_in),
      .ack (ack_a_out),
      .out (a_out_net)
  );

  // Outputs
  q_flop qf_a_and_r (
      .rst (start),
      .clk (clk),
      .data(a_and_r_in),
      .ack (ack_a_and_r),
      .out (a_and_r)
  );
  q_flop qf_f (
      .rst (start),
      .clk (clk),
      .data(f_in),
      .ack (ack_f),
      .out (f)
  );

  // Local Clock
  q_clock qc (
      .clk(clk),
      .ack(ack)
  );
  muller_c_four rendezvous (
      .a  (ack_r_in),
      .b  (ack_a_out),
      .c  (ack_a_and_r),
      .d  (ack_f),
      .out(ack)
  );

  and #1  (
      a_and_r_net1, r_in_net, ~a_and_r, ~a_out_net
  ), (
      a_and_r_net2, a_and_r, ~a_out_net, f
  ), (
      a_and_r_net3, r_in_net, a_and_r, a_out_net
  ), (
      f_net1, r_in_net, ~r_out, ~a_in, ~a_out_net
  ), (
      f_net2, r_out, a_in, ~a_out_net, f
  ), (
      f_net3, ~r_in_net, r_out, a_in, a_out_net
  ), (
      f_net4, ~r_out, ~a_in, a_out_net, f
  );
  or #1  (
      a_and_r_net, a_and_r_net1, a_and_r_net2, a_and_r_net3
  ), (
      f_net, f_net1, f_net2, f_net3, f_net4
  );
  and #1  (
      r_in_in, r_in, ~rst
  ), (
      a_out_in, a_out, ~rst
  ), (
      a_and_r_in, a_and_r_net, ~rst
  ), (
      f_in, f_net, ~rst
  );
  buf (r_out, a_and_r), (a_in, a_and_r);

endmodule

