  tx_done <= 1'b1; 
  tx_a <= y; 
  end 
  if (x_carry || y_carry) 
  begin 
  x <= x_carry ? x_adder[255:0] : x; 
  y <= y_carry ? y_adder[255:0] : y; 
  x_carry <= 1'b0; 
  y_carry <= 1'b0; 
  end 
  else if (u_even || v_even) 
  begin 
  if (u_even) 
  begin 
  u <= u >> 1; 
  if (x[0] == 1'b0) 
  x <= x >> 1; 
  else 
  x <= x_adder[256:1]; 
  end 
  if (v_even) 
  begin 
  v <= v >> 1; 
  if (y[0] == 1'b0) 
  y <= y >> 1; 
  else 
  y <= y_adder[256:1]; 
  end 
  end 
  else 
  begin 
  if (u_minus_v[256] == 1'b0) 
  begin 
  u <= u_minus_v; 
  x <= x_adder[255:0]; 
  x_carry <= x_adder[256]; 
  end 
  else 
  begin 
  v <= v_minus_u; 
  y <= y_adder[255:0]; 
  y_carry <= y_adder[256]; 
  end 
  end 
  if (reset) 
  begin 
  u <= rx_a; 
  v <= rx_p; 
  x <= 256'd1; 
  y <= 256'd0; 
  x_carry <= 1'b0; 
  y_carry <= 1'b0; 
  tx_done <= 1'b0; 
  end 
  end 
 endmodule

