module origen_126668(
    input [31:0] A, B,
    input [2:0] adder_type,
    output reg [31:0] S,
    output reg C
);

    // Half Adder
    function [1:0] half_adder;
        input a, b;
        begin
            half_adder[0] = a ^ b; // Sum
            half_adder[1] = a & b; // Carry
        end
    endfunction

    // Full Adder
    function [1:0] full_adder;
        input a, b, cin;
        begin
            full_adder[0] = a ^ b ^ cin; // Sum
            full_adder[1] = (a & b) | (cin & (a ^ b)); // Carry
        end
    endfunction

    // Ripple-Carry Adder
    function [32:0] ripple_carry_adder;
        input [31:0] a, b;
        reg [32:0] temp;
        integer i;
        begin
            temp[0] = 0;
            for (i = 0; i < 32; i = i + 1) begin
                temp[i+1:i] = full_adder(a[i], b[i], temp[i]);
            end
            ripple_carry_adder = temp;
        end
    endfunction

    // Carry-Lookahead Adder
    function [32:0] carry_lookahead_adder;
        input [31:0] a, b;
        reg [31:0] G, P, C;
        reg [32:0] temp;
        integer i;
        begin
            for (i = 0; i < 32; i = i + 1) begin
                G[i] = a[i] & b[i];
                P[i] = a[i] | b[i];
            end
            C[0] = 0;
            for (i = 1; i < 32; i = i + 1) begin
                C[i] = G[i-1] | (P[i-1] & C[i-1]);
            end
            for (i = 0; i < 32; i = i + 1) begin
                temp[i] = a[i] ^ b[i] ^ C[i];
            end
            temp[32] = G[31] | (P[31] & C[31]);
            carry_lookahead_adder = temp;
        end
    endfunction

    // Carry-Select Adder
    function [32:0] carry_select_adder;
        input [31:0] a, b;
        reg [15:0] sum0_low, sum1_low;
        reg [15:0] sum0_high, sum1_high;
        reg [32:0] temp;
        begin
            temp[16:0] = ripple_carry_adder(a[15:0], b[15:0]);
            {sum0_high, sum0_low} = ripple_carry_adder(a[31:16], b[31:16]);
            {sum1_high, sum1_low} = ripple_carry_adder(a[31:16], b[31:16] + 1);
            temp[31:16] = temp[16] ? sum1_high : sum0_high;
            temp[32] = temp[16] ? (|sum1_high) : (|sum0_high);
            carry_select_adder = temp;
        end
    endfunction

    // Carry-Skip Adder
    function [32:0] carry_skip_adder;
        input [31:0] a, b;
        reg [32:0] temp;
        reg [3:0] P;
        integer i;
        begin
            temp = ripple_carry_adder(a, b);
            P[0] = &(a[7:0] | b[7:0]);
            P[1] = &(a[15:8] | b[15:8]);
            P[2] = &(a[23:16] | b[23:16]);
            P[3] = &(a[31:24] | b[31:24]);
            if (P[0]) temp[8] = temp[0];
            if (P[1]) temp[16] = temp[8];
            if (P[2]) temp[24] = temp[16];
            if (P[3]) temp[32] = temp[24];
            carry_skip_adder = temp;
        end
    endfunction

    always @(*) begin
        case (adder_type)
            3'b000: {C, S} = {{31{1'b0}}, half_adder(A[0], B[0])};
            3'b001: {C, S} = {{31{1'b0}}, full_adder(A[0], B[0], 1'b0)};
            3'b010: {C, S} = ripple_carry_adder(A, B);
            3'b011: {C, S} = carry_lookahead_adder(A, B);
            3'b100: {C, S} = carry_select_adder(A, B);
            3'b101: {C, S} = carry_skip_adder(A, B);
            default: {C, S} = 33'b0;
        endcase
    end

endmodule

