 `ifdef SIMULATION 
 initial baudrate_counter_ff = 4'd14; 
 `endif 
 always @(posedge clk) begin 
  if (trig_baud16) 
  baudrate_counter_ff <= baudrate_counter_ff + 1; 
 end 
 reg trig_baud_ff; 
 always @(posedge clk) begin 
  trig_baud_ff <= trig_baud16 && (baudrate_counter_ff == 4'd0); 
 end 
 assign trig_baud = trig_baud_ff; 
