module origen_075064(
    input [5:0] op_code,
    output reg [1:0] RegDst,
    output reg Jump,
    output reg Branch,
    output reg MemRead,
    output reg [1:0] MemtoReg,
    output reg [1:0] ALUop,
    output reg MemWrite,
    output reg ALUsrc,
    output reg RegWrite
);

always @(*) begin
    case(op_code)
        6'b000000: begin // R-type
            #5;
            RegDst = 2'b01;
            Jump = 1'b0;
            Branch = 1'b0;
            MemRead = 1'b0;
            MemtoReg = 2'b00;
            ALUop = 2'b10;
            MemWrite = 1'b0;
            ALUsrc = 1'b0;
            RegWrite = 1'b1;
        end
        6'b001000: begin // ADDI
            #5;
            RegDst = 2'b00;
            Jump = 1'b0;
            Branch = 1'b0;
            MemRead = 1'b0;
            MemtoReg = 2'b00;
            ALUop = 2'b00;
            MemWrite = 1'b0;
            ALUsrc = 1'b1;
            RegWrite = 1'b1;
        end
        6'b100011: begin // LW
            #5;
            RegDst = 2'b00;
            Jump = 1'b0;
            Branch = 1'b0;
            MemRead = 1'b1;
            MemtoReg = 2'b01;
            ALUop = 2'b00;
            MemWrite = 1'b0;
            ALUsrc = 1'b1;
            RegWrite = 1'b1;
        end
        6'b101011: begin // SW
            #5;
            RegDst = 2'bxx;
            Jump = 1'b0;
            Branch = 1'b0;
            MemRead = 1'b0;
            MemtoReg = 2'bxx;
            ALUop = 2'b00;
            MemWrite = 1'b1;
            ALUsrc = 1'b1;
            RegWrite = 1'b0;
        end
        6'b000100: begin // Branch
            #5;
            RegDst = 2'bxx;
            Jump = 1'b0;
            Branch = 1'b1;
            MemRead = 1'b0;
            MemtoReg = 2'bxx;
            ALUop = 2'b01;
            MemWrite = 1'b0;
            ALUsrc = 1'b0;
            RegWrite = 1'b0;
        end
        6'b000011: begin // Jump
            #5;
            RegDst = 2'bxx;
            Jump = 1'b1;
            Branch = 1'b0;
            MemRead = 1'b0;
            MemtoReg = 2'bxx;
            ALUop = 2'bxx;
            MemWrite = 1'b0;
            ALUsrc = 1'bx;
            RegWrite = 1'b0;
        end
        6'b001100: begin // ANDI
            #5;
            RegDst = 2'b00;
            Jump = 1'b0;
            Branch = 1'b0;
            MemRead = 1'b0;
            MemtoReg = 2'b00;
            ALUop = 2'b11;
            MemWrite = 1'b0;
            ALUsrc = 1'b1;
            RegWrite = 1'b1;
        end
        default: begin
            #5;
            RegDst = 2'bxx;
            Jump = 1'bx;
            Branch = 1'bx;
            MemRead = 1'bx;
            MemtoReg = 2'bxx;
            ALUop = 2'bxx;
            MemWrite = 1'bx;
            ALUsrc = 1'bx;
            RegWrite = 1'bx;
        end
    endcase
end

endmodule

