				RX_ERROR: begin
					rx_countdown <= 4;
					recv_state <= RX_DELAY_RESTART;
				end
				RX_RECEIVED: begin
					recv_state <= RX_IDLE;
				end
			endcase

			// TX State Machine
			case (tx_state)
				TX_IDLE: begin
					if (transmit) begin
						tx_data <= tx_byte;
						tx_clk_divider <= CLOCK_DIVIDE;
						tx_countdown <= 2;
						tx_out <= 0;
						tx_bits_remaining <= 8;
						tx_state <= TX_SENDING;
					end
				end
				TX_SENDING: begin
					if (tx_countdown == 0) begin
						if (tx_bits_remaining > 0) begin
							tx_bits_remaining <= tx_bits_remaining - 1;
							tx_out <= tx_data[0];
							tx_data <= {1'b0, tx_data[7:1]};
							tx_countdown <= 2;
						end else begin
							tx_out <= 1;
							tx_countdown <= 4;
							tx_state <= TX_DELAY_RESTART;
