    parameter CNT_TIME = 2400_000  //0.1s
) (
    input  wire       clk_24m,
    input  wire       rst_n,
    input  wire [7:0] num,
    output wire [7:0] sm_seg,
    output wire [3:0] sm_bit
);

  reg [ 7:0] num_in;
  reg [24:0] cnt;
  reg [ 3:0] addr;
  reg [ 3:0] sm_bit1_num;
  reg [ 3:0] sm_bit2_num;
  reg [ 3:0] sm_bit3_num;
  reg [ 3:0] sm_bit4_num;
