    sm_bit1_num = 4'b0;
    if (num > 99) begin
      num_in = num - 8'd100;
      sm_bit3_num = sm_bit3_num + 1;
    end
    repeat (10) begin
      if (num_in > 8'd9) begin
        sm_bit2_num = sm_bit2_num + 4'd1;
        num_in = num_in - 8'd10;
      end else begin
        sm_bit1_num = num_in[3:0];
      end
    end
  end
  /*always@(posedge clk_24m or negedge rst_n)
begin
