  always @(posedge clk_24m or negedge rst_n) begin
    if (!rst_n) cnt_w <= 18'd0;
    else if (cnt_w == 18'b111_111_111_111_111_111)
      // else if(&cnt_w)  
      cnt_w <= 18'd0;
    else cnt_w <= cnt_w + 1;
  end

  always @(posedge clk_24m or negedge rst_n) begin
    if (!rst_n) sm_seg_num <= 4'h0;
    else begin
      case (cnt_w[17:16])
        2'b00: sm_seg_num <= sm_bit1_num;
        2'b01: sm_seg_num <= sm_bit2_num;
        2'b10: sm_seg_num <= sm_bit3_num;
        2'b11: sm_seg_num <= sm_bit4_num;
      endcase
    end
  end

  always @(posedge clk_24m or negedge rst_n) begin
    if (!rst_n) sm_bit_reg <= 4'b1111;
    else begin
      case (cnt_w[17:16])
        2'b00: sm_bit_reg <= 4'b1110;
        2'b01: sm_bit_reg <= 4'b1101;
        2'b10: sm_bit_reg <= 4'b1011;
        2'b11: sm_bit_reg <= 4'b0111;
      endcase
    end
  end

  always @(*) begin
    case (sm_seg_num)
      S0: sm_seg_reg <= 8'hc0;
      S1: sm_seg_reg <= 8'hf9;
      S2: sm_seg_reg <= 8'ha4;
      S3: sm_seg_reg <= 8'hb0;
      S4: sm_seg_reg <= 8'h99;
      S5: sm_seg_reg <= 8'h92;
      S6: sm_seg_reg <= 8'h82;
