    reg                  s_axis_tready_reg = 1'b0;

    reg [DATA_WIDTH-1:0] m_axis_tdata_reg  = {DATA_WIDTH{1'b0}};
    reg [KEEP_WIDTH-1:0] m_axis_tkeep_reg  = {KEEP_WIDTH{1'b0}};
    reg                  m_axis_tvalid_reg = 1'b0, m_axis_tvalid_next;
    reg                  m_axis_tlast_reg  = 1'b0;
    reg [ID_WIDTH-1:0]   m_axis_tid_reg    = {ID_WIDTH{1'b0}};
    reg [DEST_WIDTH-1:0] m_axis_tdest_reg  = {DEST_WIDTH{1'b0}};
    reg [USER_WIDTH-1:0] m_axis_tuser_reg  = {USER_WIDTH{1'b0}};

    // datapath control
    reg store_axis_input_to_output;

    assign s_axis_tready = s_axis_tready_reg;

    assign m_axis_tdata  = m_axis_tdata_reg;
    assign m_axis_tkeep  = KEEP_ENABLE ? m_axis_tkeep_reg : {KEEP_WIDTH{1'b1}};
    assign m_axis_tvalid = m_axis_tvalid_reg;
    assign m_axis_tlast  = LAST_ENABLE ? m_axis_tlast_reg : 1'b1;
    assign m_axis_tid    = ID_ENABLE   ? m_axis_tid_reg   : {ID_WIDTH{1'b0}};
    assign m_axis_tdest  = DEST_ENABLE ? m_axis_tdest_reg : {DEST_WIDTH{1'b0}};
    assign m_axis_tuser  = USER_ENABLE ? m_axis_tuser_reg : {USER_WIDTH{1'b0}};

    // enable ready input next cycle if output buffer will be empty
    wire s_axis_tready_early = !m_axis_tvalid_next;

    always @* begin
        // transfer sink ready state to source
        m_axis_tvalid_next = m_axis_tvalid_reg;

        store_axis_input_to_output = 1'b0;

        if (s_axis_tready_reg) begin
            m_axis_tvalid_next = s_axis_tvalid;
            store_axis_input_to_output = 1'b1;
        end else if (m_axis_tready) begin
            m_axis_tvalid_next = 1'b0;
        end
    end

    always @(posedge clk) begin
        if (rst) begin
            s_axis_tready_reg <= 1'b0;
            m_axis_tvalid_reg <= 1'b0;
        end else begin
            s_axis_tready_reg <= s_axis_tready_early;
            m_axis_tvalid_reg <= m_axis_tvalid_next;
        end

        // datapath
        if (store_axis_input_to_output) begin
            m_axis_tdata_reg <= s_axis_tdata;
            m_axis_tkeep_reg <= s_axis_tkeep;
            m_axis_tlast_reg <= s_axis_tlast;
            m_axis_tid_reg   <= s_axis_tid;
            m_axis_tdest_reg <= s_axis_tdest;
            m_axis_tuser_reg <= s_axis_tuser;
        end
    end

end else begin
    // bypass

    assign m_axis_tdata  = s_axis_tdata;
    assign m_axis_tkeep  = KEEP_ENABLE ? s_axis_tkeep : {KEEP_WIDTH{1'b1}};
    assign m_axis_tvalid = s_axis_tvalid;
    assign m_axis_tlast  = LAST_ENABLE ? s_axis_tlast : 1'b1;
    assign m_axis_tid    = ID_ENABLE   ? s_axis_tid   : {ID_WIDTH{1'b0}};
    assign m_axis_tdest  = DEST_ENABLE ? s_axis_tdest : {DEST_WIDTH{1'b0}};
    assign m_axis_tuser  = USER_ENABLE ? s_axis_tuser : {USER_WIDTH{1'b0}};

    assign s_axis_tready = m_axis_tready;

end

endgenerate

endmodule

files.origen_026835.v:
module origen_026835 (
    input [31:0] ins,
    output reg store_imm,
    output reg ALU_src,
    output reg mem2reg,
    output reg reg_write,
    output reg mem_read,
    output reg mem_write,
    output reg [1:0] ALU_op0,
    output reg [1:0] ALU_op1
);

    wire [5:0] opcode;
    assign opcode = ins[5:0];

    always @(*) begin
        case(opcode)
            6'b000011: begin // Load instruction
                store_imm = 1'b0;
                ALU_src = 1'b1;
                mem2reg = 1'b1;
                reg_write = 1'b1;
                mem_read = 1'b1;
                mem_write = 1'b0;
                ALU_op0 = 2'b00;
                ALU_op1 = 2'b00;
            end
            6'b100011: begin // Store instruction
                store_imm = 1'b1;
                ALU_src = 1'b1;
                mem2reg = 1'bx;
                reg_write = 1'b0;
                mem_read = 1'b0;
                mem_write = 1'b1;
                ALU_op0 = 2'b00;
                ALU_op1 = 2'b00;
            end
            6'b010011: begin // Immediate arithmetic instruction
                store_imm = 1'b0;
                ALU_src = 1'b1;
                mem2reg = 1'b0;
                reg_write = 1'b1;
                mem_read = 1'b0;
                mem_write = 1'b0;
                ALU_op0 = 2'b10;
                ALU_op1 = 2'b00;
            end
            6'b110011: begin // Register-type arithmetic instruction
                store_imm = 1'b0;
                ALU_src = 1'b0;
                mem2reg = 1'b0;
                reg_write = 1'b1;
                mem_read = 1'b0;
                mem_write = 1'b0;
                ALU_op0 = 2'b10;
                ALU_op1 = 2'b00;
            end
            default: begin
                store_imm = 1'bx;
                ALU_src = 1'bx;
                mem2reg = 1'bx;
                reg_write = 1'bx;
                mem_read = 1'bx;
                mem_write = 1'bx;
                ALU_op0 = 2'bxx;
                ALU_op1 = 2'bxx;
            end
        endcase
    end

endmodule

module testbench;
    reg [31:0] ins;
    wire store_imm, ALU_src, mem2reg, reg_write, mem_read, mem_write;
    wire [1:0] ALU_op0, ALU_op1;

    control_unit dut (
        .ins(ins),
        .store_imm(store_imm),
        .ALU_src(ALU_src),
        .mem2reg(mem2reg),
        .reg_write(reg_write),
        .mem_read(mem_read),
        .mem_write(mem_write),
        .ALU_op0(ALU_op0),
        .ALU_op1(ALU_op1)
    );

    initial begin
        // Test Load instruction
        ins = 32'b00000000000000000000000000000011;
        #10;

        // Test Store instruction
        ins = 32'b00000000000000000000000000100011;
        #10;

        // Test Immediate arithmetic instruction
        ins = 32'b00000000000000000000000000010011;
        #10;

        // Test Register-type arithmetic instruction
        ins = 32'b00000000000000000000000000110011;
        #10;

        $finish;
    end

    initial begin
        $monitor("Time=%0t ins=%b store_imm=%b ALU_src=%b mem2reg=%b reg_write=%b mem_read=%b mem_write=%b ALU_op0=%b ALU_op1=%b",
                 $time, ins, store_imm, ALU_src, mem2reg, reg_write, mem_read, mem_write, ALU_op0, ALU_op1);
    end
endmodule

