module autovcoder_000122 (
    clk,
    rst_n,
    wr,
    rd,
    din,
    dout,
    full,
    empty
);
  input clk, rst_n;
  input wr, rd;
  input [7:0] din;
  output [7:0] dout;
  reg [7:0] dout;
  output full, empty;
  reg full, empty;

  reg [7:0] mem[15:0];
  reg [3:0] wp, rp;

  always @(posedge clk or negedge rst_n)
    if (!rst_n) wp <= 0;
    else begin
      if (!full && wr) wp <= wp + 1'b1;
    end

  always @(posedge clk) if (!full && wr) mem[wp] <= din;

  always @(posedge clk or negedge rst_n)
    if (!rst_n) rp <= 0;
    else begin
      if (!empty && rd) rp <= rp + 1'b1;
    end

  always @(posedge clk) if (!empty && rd) dout <= mem[rp];

  always @(posedge clk or negedge rst_n)
    if (!rst_n) full <= 1'b0;
    else begin
      if ((!rd && wr) && ((wp == rp - 1'b1) || ((rp == 4'h0) && (wp == 4'hf)))) full <= 1'b1;
      else if (full && rd) full <= 1'b0;
      else full <= 1'b0;
    end

  always @(posedge clk or negedge rst_n)
    if (!rst_n) empty <= 1'b0;
    else begin
      if ((!wr && rd) && ((rp == wp - 1'b1) || ((rp == 4'hf) && (wp == 4'h0)))) empty <= 1'b1;
      else if (empty && wr) empty <= 1'b0;
      else empty <= 1'b0;
    end
endmodule

files.autovcoder_001938.v:
module autovcoder_001938 (
    out,
    E,
    F,
    clk,
    rst
);
  output [1:0] out;
  input E, F, clk, rst;
  reg [1:0] out, state, next_state;

  parameter S0 = 2'b00, S1 = 2'b01, S2 = 2'b10, S3 = 2'b11;

  // present state logic
  always @(posedge clk, negedge rst) begin
    if (!rst) state <= S0;
    else state <= next_state;

  end

  // next state logic
  always @(state, E, F) begin
    case (state)
      S0: begin
        out = S0;
        if (E == 0) next_state = S0;
        else if ({E, F} == 2'b11) next_state = S3;
        else if ({E, F} == 2'b10) next_state = S1;
      end

      S1: begin
        out = S1;
        if (E == 0) next_state = S1;
        else if ({E, F} == 2'b11) next_state = S0;
        else if ({E, F} == 2'b10) next_state = S2;
      end

      S2: begin
        out = S2;
        if (E == 0) next_state = S2;
        else if ({E, F} == 2'b11) next_state = S1;
        else if ({E, F} == 2'b10) next_state = S3;
      end

      S3: begin
        out = S3;
        if (E == 0) next_state = S3;
        else if ({E, F} == 2'b11) next_state = S2;
        else if ({E, F} == 2'b10) next_state = S0;
      end
    endcase

  end
endmodule

