module origen_052929 #(
    parameter DW = 15,
    parameter EW = 0,
    parameter MDW = 15
) (
    input wire clk,
    input wire reset,

    // Streaming sink
    input wire [DW:0] stream_data,
    input wire stream_startofpacket,
    input wire stream_endofpacket,
    input wire [EW:0] stream_empty,
    input wire stream_valid,
    output wire stream_ready,

    // Avalon-MM master
    input wire master_waitrequest,
    output wire master_write,
    output wire [MDW:0] master_writedata,

    // Control signals
    output wire inc_address,
    output wire reset_address
);

    reg [DW:0] temp_data;
    reg temp_valid;

    // Data buffering
    always @(posedge clk or posedge reset) begin
        if (reset) begin
            if (!master_waitrequest) begin
                temp_data <= {(DW+1){1'b0}};
                temp_valid <= 1'b0;
            end
        end else if (stream_ready & stream_valid) begin
            temp_data <= stream_data;
            temp_valid <= 1'b1;
        end else if (!master_waitrequest) begin
            temp_valid <= 1'b0;
        end
    end

    // Flow control
    assign stream_ready = !reset & (!temp_valid | !master_waitrequest);

    // Data forwarding
    assign master_write = temp_valid;
    assign master_writedata = temp_data;

    // Address management
    assign inc_address = stream_ready & stream_valid;
    assign reset_address = inc_address & stream_startofpacket;

endmodule

files.autovcoder_011729.v:
module autovcoder_011729 (
    input logic clk,
    input logic [31:0] address,
    input logic write,
    input logic read,
    output logic waitrequest,
    input logic [31:0] writedata,
    input logic [3:0] byteenable,
    output logic [31:0] readdata
);
  // Memory (256 x 4 x 8-bit bytes) address is 32 bits (used only 11), word is 32 bits
  // Full memory supposed to be able to store 2^30 words but we reduce it to store 2^9 (512) words.
  // 11 bits used for address as it is byte addressing.

  parameter ROM_INIT_FILE = "";
  parameter address_bit_size = 11;
  parameter reset_vector = 128; // this is word addressing. 128 * 4 = 32'h00000200 which is mapped to 0xbfc00000

  // instructions start at word 128

  // If address > BFC00000, it is instruction address and needs to be mapped to start at word 128
  // otherwise, it is a data address (keep the same)

  logic [address_bit_size - 1:0] mapped_address;

  assign mapped_address = (address >=32'hBFC00000) ? address[address_bit_size-1:0] - 32'hBFC00000+32'h00000200 : address[address_bit_size-1:0];

  // Update readdata - only available one cycle after read request

  logic [7:0] bytes[0:(2**address_bit_size-1)*4];

  assign waitrequest = 0;
  //write writedata to mapped_address word
  always @(posedge clk) begin

    if (write == 1) begin  // write
      if (byteenable[0]) bytes[mapped_address] <= writedata[7:0];
      if (byteenable[1]) bytes[mapped_address+1] <= writedata[15:8];
      if (byteenable[2]) bytes[mapped_address+2] <= writedata[23:16];
      if (byteenable[3]) bytes[mapped_address+3] <= writedata[31:24];
    end else if (read == 1) begin  // read
      readdata <= {
        byteenable[3] ? bytes[mapped_address+3] : 8'h00,
        byteenable[2] ? bytes[mapped_address+2] : 8'h00,
        byteenable[1] ? bytes[mapped_address+1] : 8'h00,
        byteenable[0] ? bytes[mapped_address] : 8'h00
      };
    end

  end

  //Initialise memory:

  initial begin
    if (ROM_INIT_FILE != "") begin  // instruction memory
      $readmemh(ROM_INIT_FILE, bytes, reset_vector * 4);  // multiply by 4 to get byte addressing
    end
  end


endmodule

files.origen_023271.v:
module origen_023271(
    input start, empty, endCRC, block, hasNext, bytes, clk, resetAll,
    input [7:0] response,
    output reg count, byteEnable, reset, loadCmd, shiftCmd, nextAddr, dataSelect, tokenSelect, oe, startCountData
);

    reg [3:0] ps, ns;

    // State definitions
    localparam IDLE = 4'd0, RESET = 4'd1, CHECK = 4'd2, LOAD_CMD = 4'd3, SHIFT_CMD = 4'd4,
               TOKEN = 4'd5, DATA_1 = 4'd6, DATA_2 = 4'd7, DATA_3 = 4'd8, NEXT_ADDR = 4'd9, WAIT_RESP = 4'd10;

    // State register
    always @(posedge clk or posedge resetAll) begin
        if (resetAll)
            ps <= IDLE;
        else
            ps <= ns;
    end

    // Next state logic
    always @(*) begin
        case (ps)
            IDLE: ns = start ? RESET : IDLE;
            RESET: ns = CHECK;
            CHECK: ns = empty ? IDLE : LOAD_CMD;
            LOAD_CMD: ns = SHIFT_CMD;
            SHIFT_CMD: ns = WAIT_RESP;
            WAIT_RESP: ns = (response == 8'h00) ? TOKEN : WAIT_RESP;
            TOKEN: ns = DATA_1;
            DATA_1: ns = bytes ? DATA_2 : (block ? DATA_3 : NEXT_ADDR);
            DATA_2: ns = DATA_1;
            DATA_3: ns = endCRC ? NEXT_ADDR : DATA_3;
            NEXT_ADDR: ns = hasNext ? CHECK : IDLE;
            default: ns = IDLE;
        endcase
    end

    // Output logic
    always @(*) begin
        reset = (ps == RESET);
        loadCmd = (ps == LOAD_CMD);
        shiftCmd = (ps == SHIFT_CMD);
        tokenSelect = (ps == TOKEN);
        startCountData = (ps == TOKEN);
        count = (ps == DATA_1) || (ps == DATA_2) || (ps == DATA_3);
        dataSelect = (ps == DATA_1) || (ps == DATA_2) || (ps == DATA_3);
        byteEnable = (ps == DATA_1) || (ps == DATA_2);
        nextAddr = (ps == NEXT_ADDR);
        oe = (ps >= LOAD_CMD) && (ps <= DATA_3);
    end

endmodule

