            s2: begin
                AluSrcA = 2'b01;
                AluSrcB = 2'b10;
                Aluop = 2'b00;
            end
            s3: begin
                MemRead = 1'b1;
                IoD = 1'b1;
            end
            s4: begin
                RegDst = 1'b0;
                RegWrite = 1'b1;
                MemtoReg = 1'b1;
            end
            s5: begin
                MemWrite = 1'b1;
                IoD = 1'b1;
            end
            s6: begin
                AluSrcA = 2'b10;
                AluSrcB = 2'b00;
                Aluop = 2'b10;
            end
            s7: begin
                RegDst = 1'b1;
                RegWrite = 1'b1;
                MemtoReg = 1'b0;
            end
            s8: begin
                AluSrcA = 2'b10;
                AluSrcB = 2'b00;
                Aluop = 2'b01;
                PcWriteCond = 1'b1;
                PcSource = 2'b01;
            end
            s9: begin
                AluSrcA = 2'b10;
                AluSrcB = 2'b10;
                Aluop = 2'b00;
            end
            s10: begin
                RegDst = 1'b0;
                RegWrite = 1'b1;
